// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { 
  getOverview, 
  getUsers, 
  getRiders, 
  getApprovedCaptains, 
  getPendingCaptains, 
  getRides, 
  approveCaptain, 
  rejectCaptain 
} from "../../services/adminApi";
import { useAuth } from "../../contexts/AuthContext";
import { Button, Typography, Box, Table, TableHead, TableBody, TableRow, TableCell, CircularProgress } from "@mui/material";

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [overview, setOverview] = useState({});
  const [activeTab, setActiveTab] = useState("overview");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    fetchOverview();
  }, []);

  const fetchOverview = async () => {
    setLoading(true);
    setError("");
    try {
      const res = await getOverview();
      setOverview(res.data);
    } catch (err) {
      console.error(err);
      setError("Failed to load overview");
    } finally {
      setLoading(false);
    }
  };

  const fetchData = async (type) => {
    setActiveTab(type);
    setLoading(true);
    setError("");
    try {
      let res;
      if (type === "users") res = await getUsers();
      if (type === "riders") res = await getRiders();
      if (type === "captains") res = await getApprovedCaptains();
      if (type === "pending") res = await getPendingCaptains();
      if (type === "rides") res = await getRides();

      // normalize response
      let list = [];
      if (type === "users") list = res?.data?.users || [];
      if (type === "riders") list = res?.data?.riders || [];
      if (type === "captains") list = res?.data?.captains || [];
      if (type === "pending") list = res?.data?.pendingCaptains || [];
      if (type === "rides") list = res?.data?.rides || [];

      setData(list);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch data");
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (id) => {
    try {
      await approveCaptain(id);
      fetchData("pending"); // refresh pending list
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to approve captain");
    }
  };

  const handleReject = async (id) => {
    try {
      await rejectCaptain(id);
      fetchData("pending"); // refresh pending list
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to reject captain");
    }
  };

  return (
    <Box p={2}>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
        <Typography variant="h4">Admin Dashboard</Typography>
        <Button variant="contained" color="error" onClick={logout}>Logout</Button>
      </Box>

      {/* Overview Buttons */}
      <Box mb={2} display="flex" gap={1}>
        <Button variant="outlined" onClick={() => fetchData("users")}>Users ({overview.users || 0})</Button>
        <Button variant="outlined" onClick={() => fetchData("riders")}>Riders ({overview.riders || 0})</Button>
        <Button variant="outlined" onClick={() => fetchData("captains")}>Approved Captains ({overview.captains || 0})</Button>
        <Button variant="outlined" onClick={() => fetchData("pending")}>Pending Captains ({overview.pendingCaptains || 0})</Button>
        <Button variant="outlined" onClick={() => fetchData("rides")}>Rides ({overview.rides || 0})</Button>
      </Box>

      {/* Loading/Error */}
      {loading && <CircularProgress />}
      {error && <Typography color="error">{error}</Typography>}

      {/* Table */}
      {!loading && data.length > 0 && (
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Name</TableCell>
              <TableCell>Email</TableCell>
              <TableCell>Mobile</TableCell>
              <TableCell>Role</TableCell>
              <TableCell>Approval Status</TableCell>
              {activeTab === "pending" && <TableCell>Actions</TableCell>}
              {activeTab === "rides" && (
                <>
                  <TableCell>Pickup</TableCell>
                  <TableCell>Drop</TableCell>
                  <TableCell>Status</TableCell>
                </>
              )}
            </TableRow>
          </TableHead>
          <TableBody>
            {data.map((item) => (
              <TableRow key={item._id || item._id}>
                <TableCell>{item.fullName || "-"}</TableCell>
                <TableCell>{item.email || "-"}</TableCell>
                <TableCell>{item.mobile || "-"}</TableCell>
                <TableCell>{item.role || "-"}</TableCell>
                <TableCell>{item.approvalStatus || "-"}</TableCell>
                {activeTab === "pending" && (
                  <TableCell>
                    <Button size="small" color="success" onClick={() => handleApprove(item._id)}>Approve</Button>
                    <Button size="small" color="error" onClick={() => handleReject(item._id)}>Reject</Button>
                  </TableCell>
                )}
                {activeTab === "rides" && (
                  <>
                    <TableCell>{item.pickup}</TableCell>
                    <TableCell>{item.drop}</TableCell>
                    <TableCell>{item.status}</TableCell>
                  </>
                )}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      )}

      {!loading && data.length === 0 && <Typography>No data found</Typography>}
    </Box>
  );
}
